def arrange_alt(list1, list2):
    max_len = max(len(list1), len(list2))
    result = []
    for i in range(max_len):
        if i < len(list1):
            result.append(list1[i])
        if i < len(list2):
            result.append(list2[i])
    return result

if __name__ == "__main__":
    print(arrange_alt([1, 2, 3], ['A']))
